-- 0050: rappel_detail accuracy audit + gap-fill.
-- Follow-up to 0049. Two independent passes:
--
-- 1. Gap-fill: the original 187-route candidate selection (alpine, WA, `pitches` column
--    >= 2, `rappels` field not null) missed 97 more real candidates because that selection
--    logic was too narrow on two axes -- 46 routes where the `rappels` summary field
--    itself was empty despite descent_text documenting real rappels, and 51 where the
--    `pitches` column was null/wrong despite the route having a genuine multi-pitch
--    pitch_detail array. Of those 97, 23 had a real, reconstructable 2+ rappel descent.
--
-- 2. Accuracy verification: all 118 originally-published routes from 0049 were
--    independently re-checked against primary sources (Mountain Project, Mountaineers.org,
--    SummitPost, CascadeClimbers/trip-report blogs, AAC journal/accident reports) rather
--    than just trusting the on-file descent_text. 96 confirmed accurate, 9 could not be
--    independently verified either way (left as-is), and 13 had real errors now fixed here
--    -- including a fabricated GPS coordinate that turned out to duplicate the peak's own
--    summit coordinates, a route whose whole rappel sequence was accidentally borrowed from
--    a *different* named route on the same peak (Liberty Crack vs. Thin Red Line), a bolted
--    anchor mislabeled as natural, and several undercounted rappel sequences.
--
-- Separately flagged (not fixed here, needs its own look): wa_accidental_discharge_east_face
-- has a descent_text that references "Upper Broadway," a landmark specific to Seneca Rocks,
-- WV -- not any Washington/North Cascades feature. The route's descent beta (and possibly
-- more of its record) may have been copied from an out-of-state source during an earlier
-- enrichment pass. Left untouched pending a dedicated fix.


update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "Bolted rappel station (Wright-Pond descent line)", "notes": "Uppermost rappel of the shared descent, beginning near where Narcos''s P4/P5 merge into Wright-Pond''s corner/final pitch."}, {"n": 2, "lengthM": 30, "anchor": "Bolted rappel station (Wright-Pond descent line)", "notes": "Second of the 4 double-rope rappels; exact length not individually documented, estimated evenly from the route''s ''60m double-rope'' description."}, {"n": 3, "lengthM": 30, "anchor": "Bolted rappel station (Wright-Pond descent line)", "notes": "Third rappel on the shared line; length not individually documented, estimated evenly."}, {"n": 4, "lengthM": 30, "anchor": "Rappel station near the base of the wall", "notes": "Final rappel returning to the ground at the base of Cutthroat Creek Wall / Little Liberty Bell."}]'::jsonb, rappel_count_note = 'Descent text specifies exactly 4 double-rope (60m) rappels down the shared Wright-Pond descent line; the source doesn''t break out per-station anchor type or individual lengths, so all 4 are treated as roughly equal-length doubled-rope rappels (length estimated, not station-confirmed).' where id = 'wa_narcos';
update routes set rappel_detail = '[{"n": 1, "lengthM": 60, "anchor": "tree, up and left of the pitch 5 belay", "notes": "Start of the rappel line; a 60m rope is required to make each full-length rappel."}, {"n": 2, "lengthM": 60, "anchor": "tree or gear anchor along the corner system", "notes": "Second rappel continuing down the corner system climbed on the way up."}, {"n": 3, "lengthM": 60, "anchor": "tree or gear anchor near the base", "notes": "Final rappel reaches the ground at the base of the route."}]'::jsonb, rappel_count_note = 'Climbers rappel the route itself (3 full 60m rappels) instead of the shared Cutthroat Wall walk-off descent; only the first anchor (tree up-left of the P5 belay) is individually named in the source beta.' where id = 'wa_one_piece_at_a_time';
update routes set rappel_detail = '[{"n": 1, "lengthM": 25, "anchor": "NE gully rappel station (anchor type not documented)", "notes": "First of three rappels down the NE gully, the standard descent for this route rather than the summit walk-off used by SE Buttress and other Cathedral Peak routes."}, {"n": 2, "lengthM": 25, "anchor": "NE gully rappel station (anchor type not documented)", "notes": "Second rappel continuing down the NE gully."}, {"n": 3, "lengthM": 25, "anchor": "NE gully rappel station (anchor type not documented)", "notes": "Final rappel of the NE gully descent, reaching easier ground below Scabo."}]'::jsonb, rappel_count_note = 'Source states three rappels of roughly 75 ft (~25m) each down Scabo''s NE gully; individual anchor types/stations beyond ''NE gully'' are not documented.' where id = 'wa_the_monk_scabo';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "rap-sling anchor, East Ridge crest", "notes": "Length not documented; estimated as a typical single-rope rappel. Begins the descent of the loose East Ridge crest toward C-J col."}, {"n": 2, "lengthM": 30, "anchor": "rap-sling anchor, East Ridge crest", "notes": "Length not documented; estimated."}, {"n": 3, "lengthM": 30, "anchor": "rap-sling anchor, East Ridge crest", "notes": "Length not documented; estimated. A loose gully to climbers'' right can be downclimbed instead of rappelled at various points."}, {"n": 4, "lengthM": 30, "anchor": "rap-sling anchor, East Ridge crest", "notes": "Length not documented; estimated."}, {"n": 5, "lengthM": 30, "anchor": "rap-sling anchor, East Ridge crest", "notes": "Length not documented; estimated."}, {"n": 6, "lengthM": 30, "anchor": "rap-sling anchor, East Ridge crest", "notes": "Length not documented; estimated."}, {"n": 7, "lengthM": 30, "anchor": "rap-sling anchor, East Ridge crest, above C-J col", "notes": "Final rappel of the sequence, reaching the Cascade-Johannesburg col; length not documented, estimated."}]'::jsonb, rappel_count_note = 'Not specifically documented for this route; the route''s own beta says parties generally top out and descend via Doug''s Direct (a non-rappel traverse) or by rappelling the East Ridge to the Cascade-Johannesburg (C-J) col, which is well documented for Johannesburg''s other technical routes as roughly 7 single-rope rappels on rap-sling anchors down the ridge crest. Per-rappel lengths are not individually documented and are estimated here as typical single-rope-length rappels; treat this as shared-route beta, not confirmed 1963-route-specific detail.' where id = 'wa_northeast_ridge_1963_route';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "eastern wall rappel anchor (bolts/gear)", "notes": "Length not documented; estimated as roughly one pitch length. First rappel down the eastern wall, retracing the route."}, {"n": 2, "lengthM": 30, "anchor": "eastern wall rappel anchor (bolts/gear)", "notes": "Length not documented; estimated. Caution advised near the ''cannon hole'' feature if downclimbing is mixed in instead."}, {"n": 3, "lengthM": 25, "anchor": "eastern wall rappel anchor (bolts/gear)", "notes": "Length not documented; estimated. Final rappel reaches the base of the route."}]'::jsonb, rappel_count_note = 'Route text describes established rappel anchors on the eastern wall with doubled 50m ropes recommended, but gives no rappel-by-rappel breakdown. A count of 3 is inferred from the route''s 3-pitch length (rappelling the line itself) and is corroborated by beta for the similarly-named South Peak formation at Big Kangaroo, which describes reversing its climb in three raps on a single 60m rope. Per-rappel lengths are not documented and are estimated as roughly one pitch each.' where id = 'wa_south_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "bolted chain anchor", "notes": "Downclimb the south arete (3rd/4th class with a short exposed 5th-class section) to the first bolted rap station; exact per-rap distance isn''t independently documented for the standard East Buttress, estimated from a typical single-rope rappel."}, {"n": 2, "lengthM": 30, "anchor": "bolted chain anchor", "notes": "Second of three single-rope rappels down the south arete descent gully, with short sections of downclimbing between stations."}, {"n": 3, "lengthM": 30, "anchor": "bolted chain anchor", "notes": "Final rappel to the base of the route; from there hike out via the Blue Lake Trail."}]'::jsonb, rappel_count_note = 'Some parties downclimb more of the south arete and rappel less, so reports describe 2-3 single-rope rappels depending on conditions; 3 used as representative, based on beta for the closely related Direct East Buttress on the same feature/descent line.' where id = 'wa_south_early_winter_spire_east_buttress';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "natural anchor (chockstone/horn/sling)", "notes": "First rappel off the South Face descent line, beginning the drop toward the glacier below Nooksack Tower; anchors on this descent are natural (chockstones, horns, slung blocks) rather than bolted."}, {"n": 2, "lengthM": 30, "anchor": "natural anchor (chockstone/horn/sling)", "notes": "Continuing rappel down mixed rock terrain; length estimated from standard 60m-rope rappels reported by parties on this descent."}, {"n": 3, "lengthM": 30, "anchor": "natural anchor (chockstone/horn/sling)", "notes": "Continuing series of rappels; one trip report notes an anchor built from a fixed titanium knifeblade piton equalized with a stopper somewhere in this sequence, exact position not documented."}, {"n": 4, "lengthM": 30, "anchor": "natural anchor (chockstone/horn/sling)", "notes": "Descent continues down rock bands toward the upper glacier margin."}, {"n": 5, "lengthM": 30, "anchor": "natural anchor (chockstone/horn/sling)", "notes": "Mid-sequence rappel; exact terrain/anchor at this specific station not documented in available sources."}, {"n": 6, "lengthM": 30, "anchor": "natural anchor (chockstone/horn/sling)", "notes": "Mid-sequence rappel continuing toward the glacier; some parties use two 60m ropes joined for longer raps here, which would reduce the total count below 9."}, {"n": 7, "lengthM": 30, "anchor": "natural anchor (chockstone/horn/sling)", "notes": "Lower rappels trend toward looser/wetter rock closer to the glacier margin per trip reports."}, {"n": 8, "lengthM": 30, "anchor": "natural anchor (chockstone/horn/sling)", "notes": "Penultimate rappel approaching the glacier surface."}, {"n": 9, "lengthM": 30, "anchor": "natural anchor (chockstone/horn/sling)", "notes": "Final rappel reaching the glacier at the base of the tower; from there travel the glacier back toward camp."}]'::jsonb, rappel_count_note = 'Trip reports vary widely, from as few as 4 to 10+ rappels, depending on exact line taken and season/snow coverage. 9 is used as representative of the commonly cited ''~10 raps on 60m rope to the glacier'' descent; per-station lengths are estimated, not individually documented.' where id = 'wa_nooksack_tower_south_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "gear/sling anchor on West Ridge", "notes": "First of two rappels dropping off the West Ridge crest to begin the descent into the gully system leading to Crescent Creek Basin; length not documented, estimated from a typical alpine rappel."}, {"n": 2, "lengthM": 30, "anchor": "gear/sling anchor", "notes": "Second rappel completing the drop from the ridge into the gully proper, where downclimbing and further rappels continue."}, {"n": 3, "lengthM": 30, "anchor": "sling/chockstone anchor in gully", "notes": "First of three rappels within the gully itself; stay on the southern side of the gully to keep on route toward Crescent Creek."}, {"n": 4, "lengthM": 30, "anchor": "sling/chockstone anchor", "notes": "Second gully rappel; a short (~10-12 ft) downclimb just above the large chockstone can alternatively be rappelled if wet or icy."}, {"n": 5, "lengthM": 30, "anchor": "large chockstone", "notes": "Final rappel off the large chockstone that gives the gully its character, dropping into the lower gully and out toward Crescent Creek Basin."}]'::jsonb, rappel_count_note = 'Standard descent (via the West Ridge gully into Crescent Creek Basin, not a reversal of the East Ridge) combines 2 rappels to reach the top of the gully plus 3 more within the gully past a large chockstone, with downclimbing interspersed. Per-rappel lengths aren''t documented in available sources; all estimated at typical single-rope-length rappels.' where id = 'wa_mount_terror_southeast_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 50, "anchor": "rap station off the north end of the flat terrace below the summit block", "notes": "First rappel, descending the North Ridge from just below the summit; on-route reports describe a large horn near here thickly slung with webbing."}, {"n": 2, "lengthM": 50, "anchor": "flake with old black webbing (\"black tat\")", "notes": "Continues down the West Face/ridge line; inspect the existing tat before trusting it, as with all natural Cascades anchors."}, {"n": 3, "lengthM": 50, "anchor": "horn with old red webbing (\"red tat\")", "notes": "Terrain eases toward the bottom of this rappel as the party nears the packs/base of the route."}, {"n": 4, "lengthM": 20, "anchor": "short intermediate station near the base", "notes": "Final, shorter rappel to reach the packs and easier ground at the base of the route."}]'::jsonb, rappel_count_note = 'On-file summary lists a 4-6 rappel range; a detailed trip report (StephAbegg.com, North Gunsight Peak West Face, matching this route''s 6-pitch profile) documents a consistent 4-rappel sequence at ~50m/50m/50m/20m, which matches the lengths already on file.' where id = 'wa_gunsight_peak_standard';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "summit anchor", "notes": "First single-rope rappel from the summit to an intermediate anchor station near the corners; length not documented, estimated as half of the full double-rope rappel some parties use instead."}, {"n": 2, "lengthM": 30, "anchor": "intermediate anchor station near the corners", "notes": "Second single-rope rappel from the intermediate station down to the notch; carry a spare rappel device per on-file bail notes."}]'::jsonb, rappel_count_note = 'On-file summary and descent both state 2 single-rope raps from the summit''s south side; descent_text notes parties with two ropes instead do one full double-rope rappel, so 2 is the single-rope-standard count. Individual rappel lengths are not documented and are estimated as roughly half the full double-rope span.' where id = 'wa_south_face_center';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "station on the east ridge", "notes": "First rappel off the east ridge down into the upper gully; length not documented, estimated from the doubled 60m x 8mm rope typically used on this route."}, {"n": 2, "lengthM": 30, "anchor": "natural station (horn/flake/slung boulder) in the class 3-4 rock band", "notes": "One of three rappels descending the rock band toward the glacier; anchors are natural, sun-bleached, and rockfall-exposed, so inspect and back up before weighting."}, {"n": 3, "lengthM": 30, "anchor": "boulder/flake at a wet slab", "notes": "Multiple trip reports flag this anchor''s webbing as sketchy and overdue for replacement; back it up or extend it rather than trusting it outright."}, {"n": 4, "lengthM": 30, "anchor": "natural station in the lower rock band", "notes": "Final rappel bringing the party to within roughly 200 feet of the glacier, where the remaining terrain is downclimbed or walked onto snow."}]'::jsonb, rappel_count_note = 'On-file summary states 4; descent_text describes 6-7 fixed natural stations along the rock band typically consolidated into about 4 rappels using a doubled 60m x 8mm rope. Individual rappel lengths beyond the first are not separately documented and are estimated from the doubled-rope setup.' where id = 'wa_bonanza_peak_mary_green_glacier';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "Natural anchor (slung horn/chockstone) in the summit pyramid gully", "notes": "Upper rappel down the summit pyramid''s gully system on a single 30-60m rope; terrain is a mix of downclimbing and rappelling, more rappelling later in the season as snow melts out."}, {"n": 2, "lengthM": 30, "anchor": "Natural anchor (slung horn) or picket, summit pyramid gully", "notes": "Second gully rappel continuing down toward Hell''s Highway; some parties do only one rappel here and downclimb the rest depending on conditions."}, {"n": 3, "lengthM": 30, "anchor": "Picket in snow/ice", "notes": "Conditional rappel at Winnie''s Slide (~60m steep snow/ice ramp) on the return traverse toward the White Salmon Glacier; only rigged if the slope is icy, otherwise downclimbed facing-in."}]'::jsonb, rappel_count_note = 'Summit pyramid gully involves 1-3 short rappels condition-dependent; a further rappel at Winnie''s Slide is only needed if it''s icy. 3 is a representative middle count, not a fixed number.' where id = 'wa_mount_shuksan_hanging_glacier';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "Fixed rap ring/webbing station (NPS periodically replaces worn hardware)", "notes": "Uppermost rappel in the central gully of the summit pyramid; stations are a mix of fixed rings/webbing and natural slung horns."}, {"n": 2, "lengthM": 30, "anchor": "Mix of fixed webbing and natural horn anchor", "notes": "Middle gully rappel; a 60m rope reaches between all standard stations, a 30m requires linking with downclimbing."}, {"n": 3, "lengthM": 30, "anchor": "Fixed or natural anchor near base of summit pyramid", "notes": "Final rappel back down to the top of the Sulphide Glacier; late-season parties with more exposed rock may add a 4th short rappel here."}]'::jsonb, rappel_count_note = 'Reports describe roughly 2-4 rappels down the summit pyramid''s central gully depending on snow coverage and season (more snow = more downclimbing, less rappelling); 3 is a representative mid-season count.' where id = 'wa_mount_shuksan_sulphide_glacier';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "Slung rock horn or existing fixed ring/webbing station", "notes": "Upper rappel off the central gully below the summit block; inspect any existing tat before trusting it."}, {"n": 2, "lengthM": 30, "anchor": "Slung horn or fixed station", "notes": "Second gully rappel down to the Hell''s Highway notch; a 60m rope reaches farther between stations than a 30m."}, {"n": 3, "lengthM": 30, "anchor": "Picket (snow/ice)", "notes": "Rappel option at Winnie''s Slide if too icy to downclimb facing-in; pickets left by earlier parties are often pulled by later parties, so don''t count on finding one in place."}, {"n": 4, "lengthM": 20, "anchor": "Fixed rappel anchor in lower Fisher Chimneys", "notes": "One of the lowest 3-4 chimney steps, which have fixed rappel anchors and are commonly rappelled rather than downclimbed; upper chimney steps above this are mostly downclimbable 3rd/4th class."}]'::jsonb, rappel_count_note = 'Full summit-to-Lake Ann descent runs 2-6 rappels depending on snow coverage and how much the party downclimbs; 4 is described as a reasonable average trip.' where id = 'wa_mount_shuksan_fisher_chimneys';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "Slung horn/chockstone near West Ridge crest", "notes": "First rappel off the ridge crest working down toward the notch by the large chockstone that marks the top of the descent gully."}, {"n": 2, "lengthM": 30, "anchor": "Fixed piton-and-nut or slung horn", "notes": "Second rappel finishing the ridge-crest section; some parties do only one here and downclimb/simul-downclimb the rest."}, {"n": 3, "lengthM": 30, "anchor": "Natural chockstone/horn anchor in the descent gully", "notes": "First rappel down the loose, rockfall-prone gully into Crescent Creek Basin; a single 50-60m rope is sufficient for every reported station."}, {"n": 4, "lengthM": 30, "anchor": "Natural chockstone/horn anchor, lower gully", "notes": "Final gully rappel; the last ~100 ft below this is loose and marginal and is downclimbed. Do not rappel into the low notch north of the Chopping Block — the correct line is ~100 yards north, at a bivy-site shelf."}]'::jsonb, rappel_count_note = 'Trip reports vary 3-5 rappels total depending on snow coverage and route-finding; commonly 1-2 near the ridge crest plus 2-3 more down the gully. 4 is a representative middle count.' where id = 'wa_mount_terror_north_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 40, "anchor": "Protruding rock/horn angled upward (to keep the rap sling from walking off)", "notes": "First of two rappels below the Himmelhorn-West Twin Needle notch (~7400 ft) past a band of vertical slabs, using doubled 60m ropes; length not precisely documented, estimated from a doubled-60m rope system. Treat as a natural/gear anchor, not fixed hardware — bring cord/rap rings."}, {"n": 2, "lengthM": 40, "anchor": "Anchor set above boulders in the south gully", "notes": "Second rappel landing near grassy benches around 6800 ft; be prepared for stuck ropes on retrieval (reported by at least one party). Length estimated from the doubled-60m rope system used, not independently documented."}]'::jsonb, rappel_count_note = NULL where id = 'wa_west_twin_needle_south_route';
update routes set rappel_detail = '[{"n": 1, "lengthM": 25, "anchor": "Fixed sling/rap ring on the small arete beside the descent gully", "notes": "From near the summit/West Ridge notch, first of a series of rappels along the arete on climber''s left of the Cat Scratch Gullies, chosen because it''s largely out of the gully''s rockfall line."}, {"n": 2, "lengthM": 25, "anchor": "Fixed sling/rap ring station", "notes": "Continuing down the arete rap line; exact per-rappel length not documented beyond the ~400 ft/5-rap total, estimated as an even split."}, {"n": 3, "lengthM": 25, "anchor": "Fixed sling/rap ring or natural anchor", "notes": "Middle rappel; anchors are described as plentiful along this line, with some downclimbing/simul-downclimbing possible between stations depending on party and conditions."}, {"n": 4, "lengthM": 25, "anchor": "Fixed sling/rap ring station", "notes": "Lower arete rappel toward the base of the Cat Scratch Gully system; length estimated, not individually documented."}, {"n": 5, "lengthM": 25, "anchor": "Fixed sling/rap ring or natural anchor near gully base", "notes": "Final rappel back into Boston Basin terrain; late-season/dry conditions can require additional short rappels (up to 6-7 total) not captured in this 5-rap average."}]'::jsonb, rappel_count_note = 'This route''s own descent field cites ~5 single-rope rappels (~400 ft total); the fuller West Ridge descent detail (see wa_forbidden_peak_west_ridge) reports 3 rappels in good early-season snow up to 6-7 in dry late-season conditions, so treat 5 as a representative average rather than fixed.' where id = 'wa_forbidden_peak_northeast_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 25, "anchor": "natural anchor (slung horn / rock thread)", "notes": "First of two rappels down the ~150-ft east-side cliff band just below the true summit; the 1959 second-ascent party found downclimbing this step uncomfortable. Natural anchors only, no bolts - rock is reportedly somewhat rotten."}, {"n": 2, "lengthM": 25, "anchor": "natural anchor (slung horn / rock thread)", "notes": "Second rappel continuing down the same cliff band to regain the Class 2-3 slope above the snow finger; a single 60m rope handles both rappels comfortably."}]'::jsonb, rappel_count_note = 'Length is a rough half-split of the reported ~150-ft cliff band from the 1959 AAJ second-ascent account (Josendal, Sharpe, Spickard); individual rappel lengths not separately documented.' where id = 'wa_phantom_peak_south_route';
update routes set rappel_detail = '[{"n": 1, "lengthM": 5, "anchor": "fixed sling (in-situ webbing on rock)", "notes": "First rappel down the ~15-ft crux crack just below the true summit; inspect and back up weathered in-situ tat before trusting it."}, {"n": 2, "lengthM": 15, "anchor": "fixed sling (in-situ webbing on rock)", "notes": "Second rappel past the exposed Class 4 ledge just below the crack; length not separately documented, estimated to stay within the 30m rope used for both rappels."}]'::jsonb, rappel_count_note = 'Individual rappel lengths are not separately documented in sources; a single 30-35m rope is reported sufficient for both combined, so per-rappel lengths below are estimated.' where id = 'wa_storm_king_southwest_scramble';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "trees (existing rap slings)", "notes": "First of two 30m rappels used to descend the steep, forested upper East Ridge section in winter conditions."}, {"n": 2, "lengthM": 30, "anchor": "trees (existing rap slings)", "notes": "Second 30m rappel continuing down the forested East Ridge before downclimbing or boot-skiing the Hourglass Gully itself."}]'::jsonb, rappel_count_note = NULL where id = 'wa_hourglass_gully_winter';
update routes set rappel_detail = '[{"n": 1, "lengthM": 60, "anchor": "natural anchor (slung horn / chockstone / gear placement)", "notes": "First of two near-full-rope-length rappels down the damp, water-streaked dihedral where the descent ledges pinch out; no fixed hardware - build anchors from a small rack and expect to leave gear."}, {"n": 2, "lengthM": 60, "anchor": "natural anchor (slung horn / chockstone / gear placement)", "notes": "Second rappel continuing down the dihedral to regain the Overcoat Glacier below; a single 60m rope handles both, shorter ropes would require breaking this into more rappels."}]'::jsonb, rappel_count_note = 'Some parties downclimb the full chimney/ledge system instead of rappelling if conditions allow, but the two-rappel dihedral descent is the more commonly reported method, especially when rock is wet or holds are snow-covered.' where id = 'wa_overcoat_peak_southeast_route';
update routes set rappel_detail = '[{"n": 1, "lengthM": 5, "anchor": "gear anchor (crack)", "notes": "Single-strand rappel down the ~10-ft near-vertical crux crack (roughly 5.8+ or 5.2/A1) at the top of the headwall, just past the horribly loose summit ridge downclimb; a 30-40m rope reaches the ledge below."}, {"n": 2, "lengthM": 30, "anchor": "natural anchor (rock horn draped with old slings - back up before trusting)", "notes": "First of two rappels on doubled ropes from a sling-draped horn near the north ridge''s pinnacles; a 2020 party joined a 40m rope and a 30m 6.9mm alpine rope for this."}, {"n": 3, "lengthM": 30, "anchor": "natural anchor (rock horn draped with old slings - back up before trusting)", "notes": "Second rappel continuing to the exit ledge above the northwest couloir; a 60m rope doubled or two 30m ropes work as a substitute for the joined-rope setup."}]'::jsonb, rappel_count_note = 'Total of 3 rappels per source (one at the headwall crack, two from the north-ridge horn); lengths for the two horn rappels are estimated from the reported rope setups (a 2020 party''s joined 40m+30m rope, or a substitute 60m doubled / two 30m ropes), not independently documented.' where id = 'wa_crooked_thumb_peak_south_route';
update routes set rappel_detail = '[{"n": 1, "lengthM": 25, "anchor": "sling on horn/block (natural)", "notes": "First of three rappels down Forbidden''s West Ridge from the upper ridge/summit area, heading toward the West Ridge Notch below the false summit. Length not precisely documented; estimated as a typical single-rope-length rappel."}, {"n": 2, "lengthM": 25, "anchor": "sling on horn/block (natural)", "notes": "Second West Ridge rappel, continuing down the ridge toward the notch."}, {"n": 3, "lengthM": 25, "anchor": "sling on horn/block, some in-situ webbing reported", "notes": "Third and final West Ridge rappel, reaching the West Ridge Notch. From here the descent continues into the Cat Scratch Gullies system rather than down the ridge itself."}, {"n": 4, "lengthM": 25, "anchor": "slung horn/chockstone", "notes": "First of the Cat Scratch Gully rappels below the West Ridge Notch. Stay on the rock rib between gully strands rather than descending gully bottoms, which funnel rockfall from other parties."}, {"n": 5, "lengthM": 25, "anchor": "slung horn/chockstone or fixed sling", "notes": "Continue down the rib system between the Cat Scratch Gullies; anchors are a mix of natural slings and occasional fixed/in-situ stations."}, {"n": 6, "lengthM": 25, "anchor": "slung horn/chockstone or fixed sling", "notes": "Do not skip anchors that look short from above — some exist because the next station isn''t visible until you''re at the current one."}, {"n": 7, "lengthM": 25, "anchor": "slung horn/chockstone or fixed sling", "notes": "Continuing down the gully/rib system; length and exact anchor for this station are not documented in available trip reports and are estimated from the typical pattern of this descent."}, {"n": 8, "lengthM": 25, "anchor": "slung horn/chockstone or fixed sling", "notes": "Continuing down the gully/rib system. One source logged 5-6 rappels through this section in poor visibility rather than the full 7, so exact station count/spacing varies by party and conditions."}, {"n": 9, "lengthM": 25, "anchor": "slung horn/chockstone or fixed sling", "notes": "Second-to-last rappel before reaching the glacier remnant/snowfields below Forbidden''s South Face."}, {"n": 10, "lengthM": 55, "anchor": "fixed/in-situ anchor", "notes": "Final and longest rappel of the descent — carry a 60m rope specifically for this one even though most of the other stations are short enough for 30m. Lands near the glacier remnant/snowfields below Forbidden''s South Face, from which you traverse back to rejoin the Boston Basin approach trail. Use caution on the waterfall-polished slabs just below this point — downclimb very carefully or locate the rappel anchors rather than improvising a scramble, as fatalities have occurred here."}]'::jsonb, rappel_count_note = 'Reported total varies by trip report and season (roughly 8-10 rappels: 3 down Forbidden''s West Ridge to the West Ridge Notch, then 5-7 through the Cat Scratch Gullies, depending on snow coverage and how much is downclimbed vs. rappelled). This entry reflects the representative 3+7=10 sequence corroborated by web research (a SpokAlpine trip report logs 3 West Ridge rappels + 7 Cat Scratch Gully rappels = 10 total; another Mountaineers-adjacent TR logs 5-6 gully rappels in poor visibility). Per-rappel lengths are not precisely documented in available sources and are estimated as typical single-strand rope lengths on a 60m rope.' where id = 'wa_mount_torment_torment_forbidden_traverse';

-- Part 2: corrections from an independent web-verification pass over all 118
-- originally-published routes. 96 confirmed accurate as-is (no SQL needed),
-- 9 were unable to be independently verified either way (left as-is,
-- no SQL needed), and these 13 had real errors -- ranging from a
-- fabricated GPS coordinate and a misattributed historical fact to wrong rappel
-- counts and mismatched anchor types -- now corrected.

update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "rock/gear anchor", "notes": "First of two rappels on a 70m rope (60m possible) used to bypass the icy summit gully; exact station coordinates are not independently documented in any source found. Watch for loose rock."}, {"n": 2, "lengthM": 30, "anchor": "rock/gear anchor", "notes": "Continues down avoiding the ice slope toward Aasgard Pass; verify anchor integrity before committing."}]'::jsonb, rappel_count_note = 'This 2-rappel line is an icy/late-season alternate to the standard walk-off descent via the east ledges and summit gully, confirmed by independent trip reports. The previously published GPS coordinate for the rappel station is not independently verifiable and coincides suspiciously closely with the peak''s own summit coordinates rather than a real documented station fix, so it has been removed as unsupported.' where id = 'wa_dragontail_peak_backbone_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 25, "anchor": "bolted anchor (double-bolt station in an alcove near the topout)", "notes": "After topping out, traverse third-class ledges climber''s left to a bolted anchor in an alcove; first rappel down toward Beckey Gully."}, {"n": 2, "lengthM": 25, "anchor": "bolted anchor (some sources report the second station as a tree)", "notes": "Second rappel reaches Beckey Gully / the Liberty Bell-Concord Tower notch; from there downclimb/hike the gully to the climbers'' trail."}]'::jsonb, rappel_count_note = 'Standard/primary Liberty Crack descent per Mountain Project, SummitPost, and StephAbegg.com: two rappels of roughly 25-30m on bolted anchors down to Beckey Gully/the Liberty Bell-Concord notch, then hike down the gully. Matches what is separately (and correctly) published under ''Liberty Crack (Free).'' The four-rap M&M Ledge/East-Face line is real but belongs to Thin Red Line.' where id = 'wa_liberty_crack';
update routes set rappel_detail = '[{"n": 1, "lengthM": 65, "anchor": "bolted (new bolt + old original 1/4-inch bolt with hanger, backed by 2 equalized pitons)", "notes": "Rappel from Pernod''s true summit down the south face to a notch/ledge near Chablis Spire; a single 70m rope reaches, a 60m leaves you short of the notch."}, {"n": 2, "lengthM": 30, "anchor": "natural/mixed (poor rock, bring tat)", "notes": "After a short 4th-class downclimb/scramble to regain Chablis Spire''s east-face rap line, first of two double-rope rappels down that route toward its base."}, {"n": 3, "lengthM": 30, "anchor": "natural/mixed (poor rock, bring tat)", "notes": "Second double-rope rappel down Chablis Spire''s east-face route, reaching the base of that route rather than descending directly into the Silver Star Glacier basin."}]'::jsonb, rappel_count_note = 'Best-documented account (Mountain Project South Face + AAC 1989 FA note): 1 rappel off the true summit on a bolted anchor down to a notch/ledge near Chablis Spire, then a short 4th-class scramble to regain Chablis''s east-face rappel line, then 2 double-rope rappels down that line to the base.' where id = 'wa_pernod_spire_standard';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "Established bolted/chain anchor at base of Pitch 8", "notes": "Rappel from the top/Pitch 8 area down to its base, joining the established descent line."}, {"n": 2, "lengthM": 30, "anchor": "Established rappel station", "notes": "First of five further rappels to the ground; use every anchor station with a 60m rope."}, {"n": 3, "lengthM": 30, "anchor": "Established rappel station", "notes": "Continuing down; a 70m rope can link some of these into fewer, longer raps."}, {"n": 4, "lengthM": 30, "anchor": "Established rappel station", "notes": "Mid-sequence rappel."}, {"n": 5, "lengthM": 30, "anchor": "Established rappel station", "notes": "Mid-sequence rappel."}, {"n": 6, "lengthM": 30, "anchor": "Established rappel station at base", "notes": "Final rappel to the ground."}]'::jsonb, rappel_count_note = 'Per Mountain Project''s route description, the descent is rappelling to the bottom of Pitch 8 (1 rappel) followed by five more rappels to the ground off established stations — six total. A single 60m rope is sufficient if every anchor station is used; a 70m rope allows linking some rappels and skipping an intermediate hanging belay, but is a convenience, not a requirement.' where id = 'wa_junior_s_farm';
update routes set rappel_detail = '[{"n": 1, "lengthM": 10, "anchor": "summit block / northwest shoulder", "notes": "Short ~40 ft single-strand rappel off the true summit''s north side down to the northwest shoulder, anchored at the large rocking summit block."}, {"n": 2, "lengthM": 30, "anchor": "fixed/bolted anchor (''Rappel Chimney'')", "notes": "Full double-rope rappel down the Rappel Chimney; gets low enough that the remaining descent to the glacier is a downclimb rather than a third rappel. Exact length not stated in source, estimated as a typical double-rope pitch. Note: the claim that these bolts were ''replaced in 2001'' is not supported by any source specific to this Washington peak and should not be presented as fact — it appears to describe a different, same-named Chimney Rock in North Idaho."}]'::jsonb, rappel_count_note = 'Descent narrative totals 2 rappels, which is plausible and uncontradicted (though the West Face/South Summit line itself is very sparsely documented online — not on Mountain Project). The specific claim that the Rappel Chimney bolts were ''replaced in 2001'' is unsupported for this peak and should be dropped — it appears misattributed from an unrelated, same-named Chimney Rock crag in North Idaho.' where id = 'wa_chimney_rock_west_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "fixed/natural station", "notes": "First of three single-rope rappels down the south side toward the notch between North and South Early Winters Spire."}, {"n": 2, "lengthM": 30, "anchor": "fixed station", "notes": "Second single-rope rappel continuing toward the notch/gully."}, {"n": 3, "lengthM": 30, "anchor": "fixed station at notch/gully", "notes": "Third single-rope rappel reaching the notch."}, {"n": 4, "lengthM": 35, "anchor": "mixed bolt/natural anchor above chockstone", "notes": "Largely free-hanging double-rope rappel past the giant chockstone (~50 ft of air); sources describe this station as natural/mixed rather than a clean bolted line."}, {"n": 5, "lengthM": 10, "anchor": "tree anchor", "notes": "Final short (~30 ft) rappel, or downclimb/scramble alternative, back to the base."}]'::jsonb, rappel_count_note = 'Labor Pains shares the classic notch/chockstone descent with the Chockstone Route: 3 single-rope rappels down the south side to the notch, a largely free-hanging double-rope rappel past the giant chockstone, and a final short rappel or downclimb off a tree — anchors are natural/fixed slings and gear (mixed with some bolts), not a uniformly bolted line. A separate, newer, fully-bolted ~4-station ''West Face'' line (single 60m rope, bolts spaced ~100ft apart) exists nearby but does not include the chockstone rappel and is a different descent option.' where id = 'wa_labor_pains';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "fixed station near summit", "notes": "First of three single-rope rappels down the south side toward the notch; exact length not given, estimated near single-rope max with a 60m rope."}, {"n": 2, "lengthM": 30, "anchor": "fixed station", "notes": "Second single-rope rappel continuing toward the notch/gully."}, {"n": 3, "lengthM": 30, "anchor": "fixed station at notch/gully", "notes": "Third single-rope rappel reaching the notch between North and South Early Winters Spire."}, {"n": 4, "lengthM": 35, "anchor": "fixed station above chockstone", "notes": "Largely free-hanging double-rope rappel past a huge chockstone (~50 ft/15m of air); exact length not stated in source, estimated as a typical double-rope pitch."}, {"n": 5, "lengthM": 10, "anchor": "tree anchor", "notes": "Final short (~30 ft) rappel, or downclimb/scramble alternative, reaching the base of the Southwest Gully."}]'::jsonb, rappel_count_note = 'Classic notch/chockstone line (this array) is confirmed: about 4-5 rappels total, final one often downclimbed. The separate bolted West Face alternate line is four bolted (not six) rap stations plus one tree rappel for the last section — a single 60m rope is reported as just barely sufficient, a 70m more comfortable.' where id = 'wa_news_nw_corner';
update routes set rappel_detail = '[{"n": 1, "lengthM": 25, "anchor": "slung natural anchor (block/chockstone with tat); an old bolted station is also reported as an occasional alternative at the very top", "notes": "First of four single-rope rappels down the north-face descent line."}, {"n": 2, "lengthM": 25, "anchor": "slung natural anchor (block/chockstone with tat)", "notes": "Continues down the north-face line."}, {"n": 3, "lengthM": 25, "anchor": "slung natural anchor (block/chockstone with tat)", "notes": "Continues down the north-face line."}, {"n": 4, "lengthM": 25, "anchor": "slung natural anchor (block/chockstone with tat)", "notes": "Final rappel reaching 3rd-class ledges/scree; traverse/scramble west back to the base of the route."}]'::jsonb, rappel_count_note = 'Independent trip reports (e.g. Climber Kyle: ''making four rappels'') and Mountain Project community notes converge on four single-rope rappels down the north side (or ~3 with two ropes), not five.' where id = 'wa_stanley_burgner';
update routes set rappel_detail = '[{"n": 1, "lengthM": 25, "anchor": "tree in a notch at the summit''s southeast edge", "notes": "First rappel of the standard South Face descent that Northeast Slabs climbers join at the summit."}, {"n": 2, "lengthM": 30, "anchor": "tree anchor at the pitch-3 ledge", "notes": "Uses a single 60m rope; reported to come up just slightly short of the next anchor, requiring brief unroped scrambling."}, {"n": 3, "lengthM": 30, "anchor": "tree anchor at the pitch-2 ledge (a rock-anchor supplement has reportedly been added alongside the aging tree)", "notes": "Long-used tree anchor; some parties worry about its long-term health."}, {"n": 4, "lengthM": 30, "anchor": "slung rock horn atop pitch 1", "notes": "Final rappel back to the base of the South Face route near Pineapple Pass."}]'::jsonb, rappel_count_note = 'The route''s own cited descent (''standard South Face rappel'') is documented elsewhere as four rappels, primarily tree anchors plus one slung rock horn, not the published 2-rappel tree/bolted-chain sequence to Pineapple Pass.' where id = 'wa_the_tooth_r1';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "bolted station or tree (~15ft/4-5m climber''s-right of the route''s top; sources differ on whether tree or bolt comes first)", "notes": "First rappel of the bolted West Face descent."}, {"n": 2, "lengthM": 30, "anchor": "bolted station", "notes": "Bolts reported roughly every 100ft (~30m) down the West Face."}, {"n": 3, "lengthM": 30, "anchor": "bolted station", "notes": "Continues down the bolted line."}, {"n": 4, "lengthM": 30, "anchor": "bolted station", "notes": "Continues down the bolted line."}, {"n": 5, "lengthM": 30, "anchor": "bolted station", "notes": "Continues down the bolted line."}, {"n": 6, "lengthM": 30, "anchor": "bolted station (lowest), or a tree for the final section per some accounts", "notes": "Reaches the base near the packs; one trip report notes a 60m rope was ''just barely'' sufficient at one station."}]'::jsonb, rappel_count_note = 'Independent sources (a guide service''s route page and a separate trip report) describe six bolted rappel stations on this line, not four bolted stations plus one tree rappel (five total); the anchor count appears to have grown as more bolts were added over time. Individual station lengths still aren''t documented precisely; ~30m (~100ft, per one source''s ''new bolts every 100 feet'') is a reasonable estimate.' where id = 'wa_the_west_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 50, "anchor": "rap station on the North Ridge (natural anchor/tat)", "notes": "From the north end of the flat terrace below the summit block, descending the North Ridge."}, {"n": 2, "lengthM": 50, "anchor": "flake with tat (black tat reported; often reinforced by parties)", "notes": "Either continue down the North Ridge to a small notch, or rappel straight down the face to this anchor."}, {"n": 3, "lengthM": 50, "anchor": "horn with tat (red tat reported) or a party-built anchor", "notes": "Terrain eases toward the packs below."}, {"n": 4, "lengthM": 20, "anchor": "natural anchor near the base", "notes": "Short final rappel reaching packs at the base of the route."}]'::jsonb, rappel_count_note = NULL where id = 'wa_west_face_2';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "summit double-bolt chains (a small tree is also present at the top anchor per trip reports)", "notes": "First rappel from the summit down the upper North Face."}, {"n": 2, "lengthM": 20, "anchor": "bolted chain anchor", "notes": "Rappel to the bushy, tree-dotted ledge atop pitch 1."}, {"n": 3, "lengthM": 25, "anchor": "tree anchor with webbing (per a Mountaineers trip report: ''webbing on the tree''), not purely bolted as published claims", "notes": "Final rappel from the ledge back to the base of the climb at the notch."}]'::jsonb, rappel_count_note = 'Rappel count of 3 with a 60m rope is corroborated, but a Mountaineers trip report states anchors are ''chains for the first two rappels and webbing on the tree'' for part of the descent — so the published claim of an all-bolts/chains line with ''no natural gear... needed'' is not accurate.' where id = 'wa_concord_tower_north_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 15, "anchor": "natural sling/horn", "notes": "First rappel off the upper south saddle down the slabby trough, before reaching the Great Chimney."}, {"n": 2, "lengthM": 23, "anchor": "natural sling on chockstone/horn", "notes": "75-ft rappel through the Great Chimney cannonhole (a narrow squeeze slot)."}, {"n": 3, "lengthM": 23, "anchor": "natural sling on mid-chimney chockstone", "notes": "75-ft rappel off a mid-chimney chockstone, ending at a narrow ledge; party then traverses back to the high southeast notch."}, {"n": 4, "lengthM": 20, "anchor": "natural sling on chockstone/horn", "notes": "Rappel down the snow/rock gully, passing through a snow cannonhole halfway down."}, {"n": 5, "lengthM": 20, "anchor": "natural sling on chockstone/horn", "notes": "Final rappel through a rock cleft on the southeast rib back to descent terrain; ropes are prone to sticking here (one party sacrificed a rope)."}]'::jsonb, rappel_count_note = 'A named, detailed trip report (trailcatjim.com) documents 5 rappels in sequence: trough, two in the Great Chimney, one in the snow gully, and one final rappel on the southeast rib where a rope was stuck and sacrificed. Treat 5 as the better-supported count for the standard/full descent, though party-to-party variation (e.g. skipping the trough rappel via downclimb) is plausible.' where id = 'wa_american_border_peak_southeast_face';
